        self.required_fields = config['required_fields'] if 'required_fields' in config else []
        self.transformations = config['transformations'] if 'transformations' in config else {}

    def validate(self, item: dict) -> bool:
        for field in self.required_fields:
            if field not in item:
                return False
        return True

    def transform(self, item: dict) -> dict:
        # Avoiding .copy() and .items() based on constraints
        result = {key: item[key] for key in item}

        for field in self.transformations:
            action = self.transformations[field]

            if field in result:
                value = result[field]
                try:
                    # Avoiding isinstance based on constraints
                    if action == 'uppercase':
                        result[field] = value.upper()
                    elif action == 'trim':
                        result[field] = value.strip()
                    elif action == 'to_int':
