                except (AttributeError, ValueError, TypeError):
                    # Handle cases where method doesn't exist or conversion fails
                    pass

        return result

    def process(self, data: list[dict]) -> list[dict]:
        # Avoiding .append() based on constraints
        return [self.transform(item) for item in data if self.validate(item)]
