        return Response(status_code=400, body={"error": "Title is required"})

    completed = body.get("completed", False)

    new_todo = Todo(id=todo_id_counter, title=title, completed=completed)
    todos_db[todo_id_counter] = new_todo
    todo_id_counter += 1

    return Response(
        status_code=201,
        body={
            "id": new_todo.id,
            "title": new_todo.title,
            "completed": new_todo.completed,
            "created_at": new_todo.created_at.isoformat(),
        },
    )


def update_todo(request: Request, path_params: Dict[str, str]) -> Response:
    todo_id = int(path_params.get("id"))

    if todo_id not in todos_db:
        return Response(status_code=404, body={"error": "Todo not found"})

    body = request.json()
    todo = todos_db[todo_id]

    if "title" in body:
        todo.title = body["title"]
    if "completed" in body:
        todo.completed = bool(body["completed"])

    return Response(
        status_code=200,
        body={
            "id": todo.id,
            "title": todo.title,
            "completed": todo.completed,
            "created_at": todo.created_at.isoformat(),
        },
    )


def delete_todo(request: Request, path_params: Dict[str, str]) -> Response:
    todo_id = int(path_params.get("id"))

    if todo_id not in todos_db:
        return Response(status_code=404, body={"error": "Todo not found"})

    del todos_db[todo_id]
    return Response(status_code=204)


# Router Configuration
def create_router() -> Router:
    router = Router()
    router.get("/todos", list_todos)
    router.post("/todos", create_todo)
    router.put("/todos/{id}", update_todo)
    router.delete("/todos/{id}", delete_todo)
    return router
